        ["algo" => 736, "uuid" => "3198d6", "name" => "pkcs11", "type" => "hsm", "status" => "active", "title" => "PKCS#11 v2.x", "description_md" => "PKCS#11 (Cryptoki) is the standard API for hardware security tokens and HSMs. v2.x is the classic version deployed in virtually all HSMs, smart cards, and PKCS#11 tokens.\n\nPKCS#11 is the lingua franca of HSMs: nShield, Thales Luna, SoftHSM2, smart cards, and TPMs all expose PKCS#11. Language bindings exist for Java (PKCS11 provider), Python (python-pkcs11), and C.", "mental_model" => "Universal HSM API -- PKCS#11 v2, HSM/smart-card standard, nShield/Luna/SoftHSM2.", "purpose" => ["hardware cryptography api (hsm/smart card)"], "good_for" => ["hsm key operations", "smart card signing", "tls offload", "certificate management"], "avoid_for" => ["software-only (use OS keystore)", "modern (pkcs11-3.0 preferred)"], "pros" => ["universal standard", "hardware protection", "vendor interop", "language bindings"], "cons" => ["complex C API", "v2.x design age"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Hardware HSM; PQ algorithms loadable with pkcs11-3.0.", "post_quantum_status" => 2, "example" => ["scenario" => "HSM TLS key signing", "input" => ["slot" => "HSM slot 0", "key" => "EC P-256 key handle"], "output" => ["sig" => "ECDSA signature from HSM"]], "flow" => ["C_Initialize", "C_OpenSession", "C_Login", "C_Sign with key handle"], "related" => ["pkcs11-3.0", "softhsm2", "opencryptoki", "tpm2.0"]],
        ["algo" => 737, "uuid" => "ab9f36", "name" => "pkcs11-3.0", "type" => "hsm", "status" => "active", "title" => "PKCS#11 v3.0", "description_md" => "PKCS#11 v3.0 adds post-quantum algorithms (ML-KEM, ML-DSA), EdDSA, X25519, HKDF, and modernized mechanism support to the classic Cryptoki API.\n\nPKCS#11 v3.0 is the forward-looking HSM API for PQ cryptography. Vendors are beginning to ship v3.0 firmware.", "mental_model" => "Modern HSM API -- PKCS#11 v3.0, PQ algorithms, EdDSA, X25519 support.", "purpose" => ["modern hsm api with pq algorithm support"], "good_for" => ["pq hsm operations", "eddsa hsm signing", "x25519 key agreement", "modern tls offload"], "avoid_for" => ["legacy HSM (v2.x compatible)"], "pros" => ["pq algorithm support", "eddsa/x25519", "modern design", "oasis standard"], "cons" => ["limited vendor support yet"], "difficulty" => 3, "security" => 5, "quantum_impact" => "ML-KEM/ML-DSA support for PQ operations.", "post_quantum_status" => 4, "example" => ["scenario" => "HSM ML-DSA signing", "input" => ["mechanism" => "CKM_ML_DSA", "key" => "ML-DSA-65 handle"], "output" => ["sig" => "ML-DSA signature"]], "flow" => ["C_SignInit(CKM_ML_DSA)", "C_Sign", "hardware PQ signature"], "related" => ["pkcs11", "softhsm2", "tpm2.0"]],
        ["algo" => 739, "uuid" => "86e4b6", "name" => "cng", "type" => "hsm", "status" => "active", "title" => "CNG", "description_md" => "CNG (Cryptography Next Generation) is the Windows cryptographic API replacing CAPI. Used by Windows TLS, BitLocker, code signing, and all Windows 10/11 crypto operations.\n\nCNG uses algorithm providers: BCryptEncrypt, BCryptSignHash, BCryptKeyDerivation. TPM integration via Platform Crypto Provider.", "mental_model" => "Windows crypto API -- CNG BCrypt/NCrypt, TPM integration, BitLocker/TLS standard.", "purpose" => ["windows cryptographic api (cng)"], "good_for" => ["windows tls", "windows code signing", "bitlocker", "tpm key storage"], "avoid_for" => ["cross-platform (openssl)", "non-windows"], "pros" => ["windows standard", "tpm integration", "hardware provider support", "bitlocker"], "cons" => ["windows-only"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Microsoft adding PQ via CNG providers.", "post_quantum_status" => 2, "example" => ["scenario" => "Windows TLS signing via CNG", "input" => ["key" => "NCrypt key handle", "hash" => "SHA-256"], "output" => ["sig" => "CNG ECDSA signature"]], "flow" => ["NCryptOpenKey", "BCryptSignHash", "optional: TPM provider"], "related" => ["capi", "tpm2.0", "pkcs11"]],
        ["algo" => 741, "uuid" => "25e98f", "name" => "tpm2.0", "type" => "hsm", "status" => "active", "title" => "TPM 2.0", "description_md" => "TPM 2.0 (Trusted Platform Module, TCG spec) is a hardware security chip in virtually all modern PCs and laptops. Provides key generation, attestation (AIK), sealed storage, and measured boot.\n\nTPM 2.0 is mandatory for Windows 11. Used for BitLocker, FIDO2 platform authenticators, Secure Boot chain, and remote attestation.", "mental_model" => "PC security chip -- TPM 2.0, Windows 11 required, BitLocker/attestation/measured boot.", "purpose" => ["hardware key protection and attestation"], "good_for" => ["windows 11 bitlocker", "fido2 platform auth", "remote attestation", "measured boot", "disk encryption key sealing"], "avoid_for" => ["general purpose HSM (use Luna/nShield)"], "pros" => ["ubiquitous in PCs", "tcg standard", "windows native", "fido2"], "cons" => ["limited key slots", "complex tcg API"], "difficulty" => 3, "security" => 5, "quantum_impact" => "TPM 2.0 adding PQ EK certs.", "post_quantum_status" => 2, "example" => ["scenario" => "TPM BitLocker key sealing", "input" => ["pcr" => "PCR[0-7]", "key" => "volume key"], "output" => ["sealed" => "TPM sealed blob"]], "flow" => ["TPM2_Create key", "TPM2_Seal to PCR values", "TPM2_Unseal on boot"], "related" => ["tpm1.2", "pkcs11", "cng", "intel-sgx"]],
        ["algo" => 742, "uuid" => "461491", "name" => "intel-sgx", "type" => "hsm", "status" => "active", "title" => "Intel SGX", "description_md" => "Intel SGX (Software Guard Extensions) is a CPU-based TEE that creates encrypted enclaves isolated from OS and hypervisor. Used for confidential computing, key protection, and privacy-preserving computation.\n\nSGX v2 (Ice Lake+) supports larger enclaves. Used in Azure Confidential Computing, Fortanix, and secret management.", "mental_model" => "CPU encrypted enclave -- Intel SGX, isolated from OS/hypervisor, confidential compute.", "purpose" => ["cpu tee for isolated secret computation"], "good_for" => ["confidential computing", "key management in cloud", "privacy computation", "secret processing"], "avoid_for" => ["high-performance (enclave overhead)", "server CPUs without SGX"], "pros" => ["hardware isolation", "os-independent", "azure cc support", "remote attestation"], "cons" => ["side-channel history", "limited EDMM memory", "cpu-specific"], "difficulty" => 4, "security" => 5, "quantum_impact" => "TEE isolation; key algorithms inside enclave.", "post_quantum_status" => 3, "example" => ["scenario" => "SGX key management", "input" => ["key" => "AES-256 key in enclave"], "output" => ["sealed" => "SGX-sealed key blob"]], "flow" => ["create enclave", "ECALL into enclave", "keys never leave in plaintext", "remote attestation via DCAP"], "related" => ["intel-tdx", "amd-sev", "arm-trustzone", "nitro-enclaves"]],
        ["algo" => 743, "uuid" => "7704fa", "name" => "intel-tdx", "type" => "hsm", "status" => "active", "title" => "Intel TDX", "description_md" => "Intel TDX (Trust Domain Extensions) is Intel's VM-level TEE technology, isolating entire VMs as Trust Domains with hardware-encrypted memory. Successor to SGX at the VM level.\n\nTDX is used in Azure/GCP/OCI confidential VMs. Unlike SGX's enclave model, TDX protects entire workloads.", "mental_model" => "Confidential VM TEE -- Intel TDX, whole VM isolation, Azure/GCP CC VMs.", "purpose" => ["vm-level tee for confidential vms"], "good_for" => ["confidential cloud vms", "lift-and-shift to TEE", "azure/gcp/oci confidential"], "avoid_for" => ["process-level isolation (sgx)"], "pros" => ["entire VM isolation", "simpler than SGX", "cloud provider support"], "cons" => ["newer (less deployed)", "hardware requirement"], "difficulty" => 3, "security" => 5, "quantum_impact" => "VM TEE; crypto inside VM.", "post_quantum_status" => 3, "example" => ["scenario" => "Azure TDX confidential VM", "input" => ["vm" => "Ubuntu 22.04 workload"], "output" => ["tdx" => "hardware-isolated VM"]], "flow" => ["launch TDX TD VM", "hardware-encrypted VM memory", "TD REPORT attestation"], "related" => ["intel-sgx", "amd-sev-snp", "arm-cca"]],
        ["algo" => 744, "uuid" => "d377d1", "name" => "amd-sev", "type" => "hsm", "status" => "active", "title" => "AMD SEV", "description_md" => "AMD SEV (Secure Encrypted Virtualization) encrypts VM memory using per-VM keys, protecting VMs from hypervisor inspection. First-generation SEV for basic memory encryption.\n\nSEV is supported on EPYC Zen 1+. Provides memory encryption but not integrity protection (SEV-SNP adds integrity).", "mental_model" => "AMD VM memory encryption -- SEV, per-VM key, hypervisor-blind VMs.", "purpose" => ["vm memory encryption (hypervisor blind)"], "good_for" => ["cloud vm memory protection", "hypervisor-untrusted environments"], "avoid_for" => ["integrity protection (use sev-snp)"], "pros" => ["vm memory encryption", "amd epyc standard", "aws/azure support"], "cons" => ["no integrity (sev-snp better)", "replay attacks possible"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Memory encryption (AES-128); VM crypto.", "post_quantum_status" => 2, "example" => ["scenario" => "EPYC SEV VM", "input" => ["vm" => "cloud workload"], "output" => ["memory" => "AES-128 encrypted per-VM key"]], "flow" => ["SEV enable on hypervisor", "each VM gets unique memory encryption key", "hypervisor sees ciphertext"], "related" => ["amd-sev-snp", "intel-tdx", "intel-sgx"]],
        ["algo" => 745, "uuid" => "c1725f", "name" => "amd-sev-snp", "type" => "hsm", "status" => "active", "title" => "AMD SEV-SNP", "description_md" => "AMD SEV-SNP (Secure Nested Paging) adds memory integrity and replay protection to SEV. Prevents hypervisor from remapping VM memory pages.\n\nSEV-SNP is the most secure AMD VM TEE. Used in AWS Nitro, Azure confidential VMs, and Google Confidential Compute.", "mental_model" => "AMD full VM TEE -- SEV-SNP, memory encryption + integrity, cloud CC standard.", "purpose" => ["secure vm tee with memory integrity"], "good_for" => ["cloud confidential vms", "aws/azure/gcp cc", "hypervisor-untrusted"], "avoid_for" => ["older EPYC (no SNP support)"], "pros" => ["memory encryption + integrity", "replay protection", "cloud standard", "remote attestation"], "cons" => ["hardware requirement (Zen 3+)"], "difficulty" => 3, "security" => 5, "quantum_impact" => "VM TEE; crypto inside VM.", "post_quantum_status" => 3, "example" => ["scenario" => "AWS SNP confidential VM", "input" => ["vm" => "EPYC Zen3 workload"], "output" => ["snp" => "memory encrypted + integrity"]], "flow" => ["SNP enable", "RMP table integrity", "SNP attestation report", "cloud VCEK cert chain"], "related" => ["amd-sev", "intel-tdx", "arm-cca", "nitro-enclaves"]],
        ["algo" => 746, "uuid" => "1d2305", "name" => "arm-trustzone", "type" => "hsm", "status" => "active", "title" => "ARM TrustZone", "description_md" => "ARM TrustZone partitions processor into Secure World and Normal World. The Secure World runs trusted firmware (OP-TEE, Secure Monitor) hosting Trusted Applications (TAs) for key storage, DRM, biometrics.\n\nTrustZone is in virtually all ARM Cortex-A SoCs: Android Keystore, iOS Secure Enclave (similar), Qualcomm QSEE, and IoT secure storage.", "mental_model" => "ARM security partition -- TrustZone, Secure/Normal World, Android Keystore/DRM.", "purpose" => ["arm soc tee for mobile/iot security"], "good_for" => ["android keystore (hw-backed)", "mobile drm (widevine l1)", "biometric keys", "iot secure storage"], "avoid_for" => ["server environments (SGX/SEV)"], "pros" => ["ubiquitous in arm", "android standard", "drm/biometric support"], "cons" => ["vendor-specific TAs", "side-channel risks"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Mobile TEE; crypto inside Secure World.", "post_quantum_status" => 2, "example" => ["scenario" => "Android Keystore hardware-backed key", "input" => ["key" => "AES-256 hw-backed"], "output" => ["ops" => "encrypt/decrypt in TrustZone"]], "flow" => ["Android KeyStore API", "TEE TA handles key ops", "key never leaves Secure World"], "related" => ["arm-cca", "apple-secure-enclave", "intel-sgx"]],
        ["algo" => 747, "uuid" => "e0f633", "name" => "arm-cca", "type" => "hsm", "status" => "active", "title" => "ARM CCA", "description_md" => "ARM CCA (Confidential Compute Architecture) introduces Realms -- hardware-isolated VMs protected from hypervisor, firmware, and OS. Part of ARMv9 architecture.\n\nCCA is ARM's answer to Intel TDX/AMD SEV-SNP for server and cloud workloads. Available on ARMv9 CPUs.", "mental_model" => "ARM VM TEE for cloud -- CCA Realms, ARMv9, hypervisor-blind isolated VMs.", "purpose" => ["armv9 vm-level tee (realms)"], "good_for" => ["arm cloud confidential vms", "armv9 server workloads"], "avoid_for" => ["older ARM (no CCA)"], "pros" => ["armv9 standard", "vm-level isolation", "cloud ready"], "cons" => ["new (limited deployment)", "ARMv9 required"], "difficulty" => 3, "security" => 5, "quantum_impact" => "VM TEE; crypto inside Realm.", "post_quantum_status" => 3, "example" => ["scenario" => "ARMv9 Realm VM", "input" => ["vm" => "workload"], "output" => ["realm" => "hypervisor-isolated"]], "flow" => ["create Realm", "hardware memory encryption/integrity", "Realm attestation token"], "related" => ["arm-trustzone", "intel-tdx", "amd-sev-snp"]],
        ["algo" => 748, "uuid" => "daf188", "name" => "apple-secure-enclave", "type" => "hsm", "status" => "active", "title" => "Apple Secure Enclave", "description_md" => "Apple Secure Enclave (SEP) is a dedicated security coprocessor in iPhone, iPad, Mac (T2/M-series). Manages Face ID/Touch ID biometrics, device encryption keys, and Apple Pay.\n\nSEP runs its own OS isolated from the main CPU. Private keys in Secure Enclave never leave the chip. Used for all iOS security-critical operations.", "mental_model" => "Apple hardware key store -- Secure Enclave, Face ID/Touch ID, Apple Pay, isolated coprocessor.", "purpose" => ["apple hardware security coprocessor"], "good_for" => ["ios/macos biometric auth", "apple pay keys", "device encryption", "passcode verification"], "avoid_for" => ["non-apple devices"], "pros" => ["hardware isolated coprocessor", "biometric integration", "apple standard", "never-extractable keys"], "cons" => ["apple-only", "limited algorithm choice"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Dedicated crypto coprocessor; classical ECDSA P-256.", "post_quantum_status" => 2, "example" => ["scenario" => "iOS Face ID key operation", "input" => ["biometric" => "Face ID data"], "output" => ["key_op" => "Secure Enclave EC P-256 signature"]], "flow" => ["SecKey API", "CryptoKit Secure Enclave key", "key operations in SEP coprocessor"], "related" => ["arm-trustzone", "tpm2.0", "pkcs11"]],
        ["algo" => 749, "uuid" => "2894b0", "name" => "nitro-enclaves", "type" => "hsm", "status" => "active", "title" => "AWS Nitro Enclaves", "description_md" => "AWS Nitro Enclaves are isolated compute environments created from EC2 instances with no persistent storage, interactive access, or external networking. Attestation via signed PCR measurements.\n\nNitro Enclaves are used for secret processing, ML model protection, and cryptographic key operations in AWS.", "mental_model" => "AWS isolated compute -- Nitro Enclaves, no storage/network, signed attestation, secrets processing.", "purpose" => ["aws isolated computation with attestation"], "good_for" => ["aws secret processing", "ml model protection", "key management in cloud", "cryptographic operations"], "avoid_for" => ["interactive compute (no ssh)", "non-AWS"], "pros" => ["no persistent storage", "cryptographic attestation", "aws kms integration", "vsock communication"], "cons" => ["aws-specific", "limited compute size"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Isolated compute; crypto inside enclave.", "post_quantum_status" => 3, "example" => ["scenario" => "AWS KMS key attestation", "input" => ["enclave" => "processing workload", "pcrs" => "signed measurements"], "output" => ["kms" => "allows key use based on attestation"]], "flow" => ["allocate enclave from EC2", "vsock communication", "PCR-based attestation", "AWS KMS policy verifies PCRs"], "related" => ["intel-sgx", "amd-sev-snp", "tpm2.0"]],
        ["algo" => 750, "uuid" => "0178d9", "name" => "nvidia-cc", "type" => "hsm", "status" => "active", "title" => "NVIDIA Confidential Computing", "description_md" => "NVIDIA Confidential Computing provides GPU TEE capabilities on H100/H200 GPUs. GPU memory is encrypted and isolated, enabling confidential ML workloads and secure inference.\n\nNVIDIA CC is the first GPU-based TEE for AI workloads. Works with AMD SEV-SNP and Intel TDX for full confidential AI.", "mental_model" => "GPU TEE for AI -- NVIDIA H100 CC, encrypted GPU memory, confidential ML.", "purpose" => ["gpu tee for confidential ai/ml workloads"], "good_for" => ["confidential ml inference", "secure ai training", "gpu-accelerated tee"], "avoid_for" => ["non-H100/H200 GPUs"], "pros" => ["gpu tee first-of-kind", "confidential ai", "h100/h200 standard", "nve attestation"], "cons" => ["H100+ required", "new ecosystem"], "difficulty" => 3, "security" => 5, "quantum_impact" => "GPU TEE for PQ crypto acceleration possible.", "post_quantum_status" => 3, "example" => ["scenario" => "Confidential LLM inference on H100", "input" => ["model" => "LLM weights (encrypted)"], "output" => ["inference" => "GPU-isolated result"]], "flow" => ["enable CC mode on H100", "encrypted GPU VRAM", "GPU attestation report"], "related" => ["intel-tdx", "amd-sev-snp", "nitro-enclaves"]],
        ["algo" => 751, "uuid" => "85d736", "name" => "java-jce", "type" => "hsm", "status" => "active", "title" => "Java JCE", "description_md" => "JCE (Java Cryptography Extension) is the Java API for cryptography. Pluggable provider architecture supports software (BC), HSM (PKCS11 Provider), and hardware implementations.\n\nJCE is the universal Java crypto API. Bouncy Castle, SunPKCS11 (HSM), and SunEC are standard providers.", "mental_model" => "Java crypto API -- JCE, pluggable providers, BouncyCastle/PKCS11/SunEC.", "purpose" => ["java cryptographic api (provider architecture)"], "good_for" => ["java app crypto", "jvm hsm via pkcs11 provider", "java tls (jsse)", "android ndk"], "avoid_for" => ["non-java platforms"], "pros" => ["java standard", "pluggable providers", "bc/pkcs11 support", "jvm portable"], "cons" => ["java only", "provider config complexity"], "difficulty" => 2, "security" => 4, "quantum_impact" => "BC PQ provider (ML-KEM/ML-DSA) available.", "post_quantum_status" => 3, "example" => ["scenario" => "Java AES-GCM with BC provider", "input" => ["provider" => "BC", "key" => "AES-256"], "output" => ["ciphertext" => "AES-GCM encrypted"]], "flow" => ["Security.addProvider(new BouncyCastleProvider())", "Cipher.getInstance('AES/GCM/NoPadding', 'BC')", "init + doFinal"], "related" => ["pkcs11", "openssl-provider", "botan-p11"]],
        ["algo" => 753, "uuid" => "8f7fa3", "name" => "openssl-provider", "type" => "hsm", "status" => "active", "title" => "OpenSSL Provider", "description_md" => "OpenSSL 3.x introduces Providers replacing the deprecated Engine API. Providers implement algorithm modules: default, legacy, FIPS, and third-party (PKCS#11, PQ).\n\nOpenSSL Providers allow HSM integration (pkcs11-provider), FIPS 140-3 (FIPS provider), and post-quantum algorithms (OQS provider).", "mental_model" => "OpenSSL 3.x modular algo plugins -- Provider API, FIPS/PKCS11/PQ providers.", "purpose" => ["openssl 3.x algorithm provider modules"], "good_for" => ["openssl fips 140-3", "openssl pkcs11 hsm", "openssl pq algorithms", "tls provider plugins"], "avoid_for" => ["openssl 1.x (use engine)"], "pros" => ["openssl 3.x standard", "fips provider certified", "pkcs11 integration", "pq oqs provider"], "cons" => ["engine migration required", "new API"], "difficulty" => 3, "security" => 5, "quantum_impact" => "OQS provider adds PQ algorithms to OpenSSL.", "post_quantum_status" => 3, "example" => ["scenario" => "OpenSSL FIPS mode", "input" => ["provider" => "FIPS", "algo" => "AES-256-GCM"], "output" => ["result" => "FIPS-validated cipher"]], "flow" => ["openssl.cnf: providers = FIPS", "EVP_default_properties_enable_fips()", "all operations via FIPS provider"], "related" => ["openssl-engine", "pkcs11", "wolfssl-fips", "libp11"]],
        ["algo" => 754, "uuid" => "7cd66e", "name" => "wolfssl-fips", "type" => "hsm", "status" => "active", "title" => "wolfSSL FIPS", "description_md" => "wolfSSL FIPS is a FIPS 140-3 validated TLS/crypto library targeting embedded and IoT systems. wolfSSL FIPS 140-3 cert #3389 covers AES-GCM, SHA-2/3, ECDSA, RSA, and HMAC.\n\nwolfSSL FIPS is the leading FIPS solution for IoT, medical devices, and automotive (AUTOSAR).", "mental_model" => "Embedded FIPS 140-3 crypto -- wolfSSL, IoT/automotive/medical standard.", "purpose" => ["fips 140-3 embedded/iot crypto library"], "good_for" => ["iot fips compliance", "automotive (autosar)", "medical device crypto", "embedded tls"], "avoid_for" => ["server-grade (openssl fips)", "non-embedded"], "pros" => ["fips 140-3 validated", "embedded/iot size", "automotive support", "rtos compatible"], "cons" => ["commercial license for FIPS"], "difficulty" => 2, "security" => 5, "quantum_impact" => "wolfSSL PQ FIPS module in development.", "post_quantum_status" => 2, "example" => ["scenario" => "IoT FIPS TLS", "input" => ["lib" => "wolfSSL FIPS", "tls" => "TLS 1.3"], "output" => ["conn" => "FIPS-validated TLS"]], "flow" => ["wolfSSL_Init()", "wolfSSL_CTX_new(wolfTLSv1_3_method())", "FIPS validated operations"], "related" => ["openssl-provider", "botan-p11", "tpm2.0"]],
        ["algo" => 755, "uuid" => "67920d", "name" => "botan-p11", "type" => "hsm", "status" => "active", "title" => "Botan PKCS#11", "description_md" => "Botan is a C++ cryptography library with first-class PKCS#11 support. Botan PKCS#11 wraps the PKCS#11 API with C++ classes for HSMs, smart cards, and hardware tokens.\n\nBotan supports PQ algorithms (ML-KEM, ML-DSA), PKCS#11, TLS 1.3, and is used in VPN, PKI, and security products.", "mental_model" => "C++ crypto with PKCS#11 -- Botan, HSM/smart card support, PQ algorithms.", "purpose" => ["c++ crypto library with pkcs#11 and pq support"], "good_for" => ["c++ hsm applications", "pq cryptography (ml-kem/ml-dsa)", "vpn/pki systems", "smart card integration"], "avoid_for" => ["non-C++ (use OpenSSL/bouncycastle)"], "pros" => ["c++ native", "pkcs#11 support", "pq algorithms", "bsd license"], "cons" => ["c++ only", "less deployed than openssl"], "difficulty" => 3, "security" => 5, "quantum_impact" => "ML-KEM/ML-DSA support included.", "post_quantum_status" => 4, "example" => ["scenario" => "Botan PKCS#11 sign", "input" => ["hsm" => "SoftHSM2 slot", "key" => "EC P-256"], "output" => ["sig" => "ECDSA via HSM"]], "flow" => ["PKCS11_Module init", "PKCS11_Slot + session", "PKCS11_PrivateKey sign"], "related" => ["pkcs11", "libp11", "openssl-provider"]],
